import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Chemical = () => {
  const [posts, setPosts] = useState([]);
  const [selectedPost, setSelectedPost] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Try both common ports
  const PORTS = ['http://localhost:5001', 'http://localhost:5000'];

  useEffect(() => {
    const fetchChemicalPosts = async () => {
      setLoading(true);
      let foundData = [];

      for (let baseUrl of PORTS) {
        try {
          // 1. Try lowercase 'chemical'
          let res = await axios.get(`${baseUrl}/api/blog/chemical`);

          // 2. If empty, try Capital 'Chemical'
          if (!res.data || res.data.length === 0) {
            res = await axios.get(`${baseUrl}/api/blog/Chemical`);
          }

          if (res.data && res.data.length > 0) {
            foundData = res.data;
            // Set global base URL for images based on which port worked
            window.WORKING_BASE_URL = baseUrl; 
            break; 
          }
        } catch (err) {
          console.error(`Failed to fetch from ${baseUrl}:`, err.message);
        }
      }

      if (foundData.length > 0) {
        setPosts(foundData);
        setSelectedPost(foundData[0]);
      } else {
        setError("No data found. Please check if your Backend is running and 'chemical' category exists.");
      }
      setLoading(false);
    };

    fetchChemicalPosts();
  }, []);

  const getImageUrl = (imagePath) => {
    const base = window.WORKING_BASE_URL || 'http://localhost:5001';
    if (!imagePath) return "https://via.placeholder.com/1200x600?text=Hudson+Chemical+Solutions";
    if (imagePath.startsWith('http')) return imagePath;
    const cleanPath = imagePath.startsWith('/') ? imagePath : `/${imagePath}`;
    return `${base}${cleanPath}`;
  };

  if (loading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-white">
      <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-gray-400 font-black tracking-widest animate-pulse">SYNCING CHEMICAL DATABASE...</p>
    </div>
  );

  return (
    <div className="bg-[#fcfcfd] min-h-screen antialiased text-slate-900 font-sans">

      {/* 1. MINIMALIST HEADER */}
      <header className="pt-24 pb-12 px-6 md:px-16 border-b border-gray-100 bg-white">
        <div className="max-w-screen-2xl mx-auto">
          <div className="flex items-center gap-2 text-xs text-emerald-600 mb-4 font-black uppercase tracking-[0.3em]">
            <span>Industries</span>
            <span className="text-gray-300">/</span>
            <span>Chemical Division</span>
          </div>
          <h1 className="text-5xl md:text-8xl font-black tracking-tighter text-gray-950 leading-[0.85]">
            Industrial <br /><span className="text-emerald-600 italic">Chemistry</span>
          </h1>
        </div>
      </header>

      {/* 2. MAIN LAYOUT */}
      <main className="max-w-screen-2xl mx-auto px-6 md:px-16 py-16">
        <div className="flex flex-col xl:flex-row gap-16">

          {/* LEFT: CONTENT AREA */}
          <div className="xl:w-2/3">
            {selectedPost ? (
              <article className="animate-fadeIn transition-all duration-700">
                <div className="rounded-[3rem] overflow-hidden bg-gray-100 mb-12 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.12)] border border-gray-100">
                  <img 
                    src={getImageUrl(selectedPost.image)} 
                    alt={selectedPost.title}
                    className="w-full h-[550px] object-cover hover:scale-105 transition-transform duration-[3s]"
                    onError={(e) => { e.target.src = "https://via.placeholder.com/1200x600?text=Image+Server+Offline"; }}
                  />
                </div>

                <div className="flex items-center gap-6 mb-10 pb-8 border-b border-gray-100">
                   <div className="px-4 py-1.5 bg-emerald-700 text-white text-[10px] font-black uppercase tracking-widest rounded-lg">
                     Technical Report
                   </div>
                   <div className="text-gray-400 font-bold text-sm">
                     {new Date(selectedPost.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}
                   </div>
                </div>

                <h2 className="text-4xl md:text-6xl font-black text-gray-950 mb-10 leading-[1.1] tracking-tighter">
                  {selectedPost.title}
                </h2>

                <div className="text-gray-700 text-xl leading-relaxed space-y-8 font-medium text-justify">
                  {selectedPost.description.split('\n').map((para, i) => (
                    <p key={i}>{para}</p>
                  ))}
                </div>
              </article>
            ) : (
              <div className="py-40 text-center bg-gray-50 rounded-[3rem] border-2 border-dashed border-gray-200">
                <div className="text-6xl mb-6 grayscale opacity-30">⚗️</div>
                <h3 className="text-2xl font-black text-gray-300 uppercase tracking-widest">No Records Found</h3>
                <p className="text-gray-400 mt-2 max-w-xs mx-auto">Make sure the category name in Admin matches "chemical" and the server is running.</p>
              </div>
            )}
          </div>

          {/* RIGHT: STICKY LIST */}
          <div className="xl:w-1/3">
            <div className="sticky top-12 space-y-8">
              <div className="flex items-center justify-between border-b border-gray-100 pb-6">
                <h3 className="text-xs font-black uppercase tracking-[0.3em] text-gray-400">Sector Updates</h3>
                <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full">{posts.length} Posts</span>
              </div>

              <div className="space-y-4 max-h-[65vh] overflow-y-auto pr-4 custom-scrollbar">
                {posts.map((post) => {
                  const isActive = selectedPost?._id === post._id;
                  return (
                    <div 
                      key={post._id}
                      onClick={() => {
                        setSelectedPost(post);
                        window.scrollTo({ top: 0, behavior: 'smooth' });
                      }}
                      className={`group p-8 rounded-[2rem] cursor-pointer transition-all duration-500 border-2 ${
                        isActive 
                        ? 'border-emerald-500 bg-emerald-50/50 shadow-xl translate-x-3' 
                        : 'border-transparent bg-white hover:bg-gray-50 shadow-sm'
                      }`}
                    >
                      <h4 className={`text-xl font-extrabold leading-tight tracking-tight ${
                        isActive ? 'text-emerald-800' : 'text-gray-900 group-hover:text-emerald-700'
                      }`}>
                        {post.title}
                      </h4>
                      <p className="text-[10px] text-gray-400 mt-4 uppercase font-black tracking-widest">
                        Ref: {new Date(post.createdAt).toLocaleDateString()}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* 3. CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="max-w-screen-2xl mx-auto">
          <div className="w-full bg-gradient-to-br from-[#0F1F1C] to-black rounded-[4rem] p-12 md:p-24 flex flex-col md:flex-row items-center justify-between text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-96 h-96 bg-emerald-600/10 rounded-full blur-[120px]"></div>

            <div className="md:w-2/3 relative z-10 text-center md:text-left">
              <h2 className="text-5xl md:text-7xl font-black mb-8 tracking-tighter leading-[0.9]">
                Pioneering <br /> <span className="text-emerald-500">Solutions.</span>
              </h2>
              <p className="text-gray-400 text-xl mb-12 max-w-xl font-medium mx-auto md:mx-0">
                Join our network of chemical engineers and safety experts working on world-class industrial projects.
              </p>
              <Link to="/careers">
                <button className="bg-emerald-600 text-white px-16 py-6 rounded-2xl font-black text-xl hover:bg-white hover:text-emerald-700 transition-all transform hover:-translate-y-1 shadow-2xl active:scale-95 uppercase tracking-widest">
                  Apply Now
                </button>
              </Link>
            </div>

            <div className="hidden md:flex md:w-1/3 justify-end relative z-10">
              <div className="h-80 w-80 border-[12px] border-white/5 rounded-full flex items-center justify-center relative">
                <span className="text-[10rem] opacity-10 filter grayscale select-none">⚗️</span>
                <div className="absolute inset-0 border-2 border-dashed border-emerald-500/20 rounded-full animate-[spin_40s_linear_infinite]"></div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Internal CSS for Custom Scrollbar */}
      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #emerald-200; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fadeIn { animation: fadeIn 0.8s ease-out forwards; }
      `}} />

    </div>
  );
};

export default Chemical;
